    "{\"#\":58,\"createdAt\":\"2019-12-15T08:30:04.385649Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":5,\"id\":{\"gr\":10},\"value\":[{\"ul\":[[{\"lit\":\"Stakeholders often don't have a means of seeing the requirements for themselves.\"}],[{\"lit\":\"Stakeholders need to review requirements and provide feedback.\"}]]}]}}}",
    "{\"#\":59,\"createdAt\":\"2019-12-15T08:30:09.529792Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":5,\"id\":{\"gr\":11},\"value\":[{\"ul\":[[{\"lit\":\"Stakeholders (esp devs/testers) are often unaware when requirements change.\"}],[{\"lit\":\"General practice: baseline, change request, request reviewed/rejected/approved, request affects reqs.\"}],[{\"lit\":\"Stakeholders (esp. PMs) don't understand why project delayed: features should provide all info to justify, blame and improve.\"}],[{\"lit\":\"Req change process often lacks transparency.\"}]]}]}}}",
    "{\"#\":60,\"createdAt\":\"2019-12-15T08:30:17.081194Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":5,\"id\":{\"gr\":20},\"value\":[{\"ul\":[[{\"lit\":\"Business have tools in which they generate valuable data. (esp. visio diagrams)\"}],[{\"lit\":\"Business want to upload relevant data (emails, presentations, etc) so that 1) all interested parties have access. 2) it has somewhere to live (archival).\"}]]}]}}}",
    "{\"#\":61,\"createdAt\":\"2019-12-15T08:30:25.723380Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":5,\"id\":{\"gr\":24},\"value\":[{\"ul\":[[{\"lit\":\"This would improve the quality of users' requirements.\"}],[{\"lit\":\"I doubt other tools have a feature like this = business opportunity.\"}]]}]}}}",
