    "{\"#\":380,\"createdAt\":\"2020-06-15T02:16:38.845023Z\",\"event\":{\"GenericReqTitleSet\":{\"id\":54,\"value\":[{\"lit\":\"I want to be able to see req status from the Req Graph\"}]}}}",
    "{\"#\":381,\"createdAt\":\"2020-06-15T02:17:15.206066Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":1,\"id\":{\"gr\":54},\"value\":[{\"lit\":\"I often look at the implication graph on the ReqDetail page and hover over nodes to see what they are. I also want to see the req status in the hover text. It's part of my workflow to inspect the web to figure out what work I need to do.\"}]}}}",
    "{\"#\":382,\"createdAt\":\"2020-06-15T02:17:42.754047Z\",\"event\":{\"GenericReqTitleSet\":{\"id\":54,\"value\":[{\"lit\":\"I want to be able to know status of reqs in the implication graph in ReqDetail\"}]}}}",
