    "{\"#\":559,\"createdAt\":\"2020-07-04T02:11:18.325037Z\",\"event\":{\"GenericReqCreate\":{\"reqId\":101,\"reqTypeId\":3,\"values\":[{\"customText\":{\"1\":[{\"lit\":\"Add the ability to view all content as a collapsed tree, where\"},{\"ul\":[[{\"lit\":\"the tree structure is either by implication or req code\"}],[{\"lit\":\"users can collapse/expand all\"}],[{\"lit\":\"users can collapse/expand one parent at a time\"}],[{\"lit\":\"it can be done within the ReqTable (bcos it's meant for bulk viewing and editing)\"}]]}],\"5\":[{\"ul\":[[{\"lit\":\"it's too hard to see or comprehend all of my content\"}],[{\"lit\":\"need ability to browse at the highest level, then navigate into more detail as desired\"}]]}]}},{\"tags\":[19]},{\"title\":[{\"lit\":\"Collapsible tree of content\"}]}]}}}",
