    "{\"#\":566,\"createdAt\":\"2020-07-04T02:16:07.453399Z\",\"event\":{\"GenericReqTitleSet\":{\"id\":13,\"value\":[{\"lit\":\"Requirement Relationships (i.e. implication)\"}]}}}",
