    "{\"#\":667,\"createdAt\":\"2020-07-16T05:55:00.667909Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":1,\"id\":{\"gr\":107},\"value\":[{\"ul\":[[{\"lit\":\"Make ShipReq work when offline\"}],[{\"lit\":\"A user should be able to bring their laptop to a sprint planning meeting, do all of their work without internet, go back to their desk, and have ShipReq upload all the changes.\"}],[{\"lit\":\"Conflict resolution will need to be possible\"}]]}]}}}",
    "{\"#\":668,\"createdAt\":\"2020-07-16T05:56:31.426357Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":5,\"id\":{\"gr\":107},\"value\":[{\"lit\":\"Not being able to get working internet in meeting rooms used to happen all the fucking time. To be able to tell a user they can do all of their work offline (without losing any functionality) is a huge selling point.\"}]}}}",
    "{\"#\":669,\"createdAt\":\"2020-07-16T05:57:17.616515Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":1,\"id\":{\"gr\":107},\"value\":[{\"ul\":[[{\"lit\":\"Make ShipReq work when offline\"}],[{\"lit\":\"A user should be able to bring their laptop to a sprint planning meeting, do all of their work without internet, go back to their desk, and have ShipReq upload all the changes.\"}],[{\"lit\":\"Conflict resolution will need to be possible\"}],[{\"lit\":\"Ideally users should also be able to reload the tab / open new tabs without internet connectivity\"}]]}]}}}",
