    "{\"#\":805,\"createdAt\":\"2020-08-05T04:49:29.540978Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":1,\"id\":{\"gr\":120},\"value\":[{\"h3\":[{\"lit\":\"From \"},{\"req\":{\"gr\":119}}]},{\"ol\":[[{\"lit\":\"Defaults are applied\"}],[{\"lit\":\"Start processing from roots and work down to leaves, for each node...\"}],[{\"lit\":\"Merge current node's manual or default values in to its children\"}],[{\"lit\":\"Start processing from leaves and working back to trees, for each node...\"}],[{\"lit\":\"Take the results of all its children, merge and (a) add to manual tag value if it differs, or (b) remove the default and add the merge results.\"}]]},{\"h3\":[{\"lit\":\"From \"},{\"req\":{\"gr\":117}}]},{\"ol\":[[{\"lit\":\"Start processing from roots and work down to leaves, for each node...\"}],[{\"lit\":\"Merge current node's manual or default values in to its children \"},{\"**\":[{\"lit\":\"unless the child has a manual value\"}]}],[{\"lit\":\"Start processing from leaves and working back to trees, for each node...\"}],[{\"lit\":\"Take the results of all its children, merge and (a) add to manual tag value if it differs, or (b) remove the default and add the merge results.\"}]]},{\"h3\":[{\"lit\":\"Done!\"}]},{\"lit\":\"Both blocks are identical except for the bold bit in the \"},{\"req\":{\"gr\":117}},{\"lit\":\" section. Applying the bold bit to \"},{\"req\":{\"gr\":119}},{\"lit\":\" doesn't change the results so I think we're good.\"}]}}}",
