    "{\"#\":854,\"createdAt\":\"2020-08-12T10:30:08.162289Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":1,\"id\":{\"gr\":131},\"value\":[{\"lit\":\"Let's start with a real-world example:\"},{\"cb\":{\"attr\":[\"render\"],\"code\":\"node[style=filled fillcolor=\\\"#eeeeee\\\"]\\nFB1 [fillcolor=\\\"#ffc905\\\" label=\\\"FB1\\\\n(#NAᵈ)\\\"]\\nMF1 [fillcolor=\\\"#ffc905\\\" label=\\\"MF1\\\\n(#NAᵈ)\\\"]\\nIV1 [fillcolor=\\\"#f5f100\\\" label=\\\"IV1\\\\n(#A)\\\" penwidth=3]\\nIV2 [fillcolor=\\\"#ffc905\\\" label=\\\"IV2\\\\n(#NAᵈ)\\\"]\\nIV3 [fillcolor=\\\"#f5f100\\\" label=\\\"IV3\\\\n(#A)\\\" penwidth=3]\\nFR1 [fillcolor=\\\"#ccf000\\\" label=\\\"FR1\\\\n(#Rᵈ)\\\"]\\nFR2 [fillcolor=\\\"#ccf000\\\" label=\\\"FR2\\\\n(#Rᵈ)\\\"]\\nFR3 [fillcolor=\\\"#ccf000\\\" label=\\\"FR3\\\\n(#Rᵈ)\\\"]\\nFR4 [fillcolor=\\\"#ccf000\\\" label=\\\"FR4\\\\n(#Rᵈ)\\\"]\\n\\nFB1 -> MF1 -> IV1 -> FR1,FR2\\nFR1 -> FR3\\nMF1 -> IV2\\nMF1 -> IV3 -> FR4\",\"lang\":\"dot\"}},{\"//\":[{\"lit\":\"(Note: Bold circle indicates a manual status; superscript ᵈ indicates a field default; later superscript ⁺ will indicate derivation.)\"}]},{\"bl\":{}},{\"lit\":\"Firstly, let's start replacing defaults with derivative tags where possible...\"},{\"ol\":[[{\"lit\":\"Apply derivation\"},{\"cb\":{\"attr\":[\"render\"],\"code\":\"node[style=filled fillcolor=\\\"#eeeeee\\\"]\\nFB1 [fillcolor=\\\"#ffc905\\\" label=\\\"FB1\\\\n(#NA⁺)\\\"]\\nMF1 [fillcolor=\\\"#ffc905\\\" label=\\\"MF1\\\\n(#NA⁺)\\\"]\\nIV1 [fillcolor=\\\"#f5f100:#ccf000\\\" label=\\\"IV1\\\\n(#A #R⁺)\\\" penwidth=3 style=wedged]\\nIV2 [fillcolor=\\\"#ffc905\\\" label=\\\"IV2\\\\n(#NAᵈ)\\\"]\\nIV3 [fillcolor=\\\"#f5f100:#ccf000\\\" label=\\\"IV3\\\\n(#A #R⁺)\\\" penwidth=3 style=wedged]\\nFR1 [fillcolor=\\\"#ccf000\\\" label=\\\"FR1\\\\n(#Rᵈ)\\\"]\\nFR2 [fillcolor=\\\"#ccf000\\\" label=\\\"FR2\\\\n(#Rᵈ)\\\"]\\nFR3 [fillcolor=\\\"#ccf000\\\" label=\\\"FR3\\\\n(#Rᵈ)\\\"]\\nFR4 [fillcolor=\\\"#ccf000\\\" label=\\\"FR4\\\\n(#Rᵈ)\\\"]\\n\\nFB1 -> MF1 -> IV1 -> FR1,FR2\\nFR1 -> FR3\\nMF1 -> IV2\\nMF1 -> IV3 -> FR4\",\"lang\":\"dot\"}}],[{\"lit\":\"Reject IV2\"},{\"cb\":{\"attr\":[\"render\"],\"code\":\"node[style=filled fillcolor=\\\"#eeeeee\\\"]\\nFB1 [fillcolor=\\\"#ccf000\\\" label=\\\"FB1\\\\n(#R⁺)\\\"]\\nMF1 [fillcolor=\\\"#ccf000\\\" label=\\\"MF1\\\\n(#R⁺)\\\"]\\nIV1 [fillcolor=\\\"#f5f100:#ccf000\\\" label=\\\"IV1\\\\n(#A #R⁺)\\\" penwidth=3 style=wedged]\\nIV2 [fillcolor=\\\"#bbbbbb\\\" label=\\\"IV2\\\\n(#REJ)\\\" penwidth=3]\\nIV3 [fillcolor=\\\"#f5f100:#ccf000\\\" label=\\\"IV3\\\\n(#A #R⁺)\\\" penwidth=3 style=wedged]\\nFR1 [fillcolor=\\\"#ccf000\\\" label=\\\"FR1\\\\n(#Rᵈ)\\\"]\\nFR2 [fillcolor=\\\"#ccf000\\\" label=\\\"FR2\\\\n(#Rᵈ)\\\"]\\nFR3 [fillcolor=\\\"#ccf000\\\" label=\\\"FR3\\\\n(#Rᵈ)\\\"]\\nFR4 [fillcolor=\\\"#ccf000\\\" label=\\\"FR4\\\\n(#Rᵈ)\\\"]\\n\\nFB1 -> MF1 -> IV1 -> FR1,FR2\\nFR1 -> FR3\\nMF1 -> IV2\\nMF1 -> IV3 -> FR4\",\"lang\":\"dot\"}}],[{\"lit\":\"Implement FR4\"},{\"cb\":{\"attr\":[\"render\"],\"code\":\"node[style=filled fillcolor=\\\"#eeeeee\\\"]\\nFB1 [fillcolor=\\\"#ccf000\\\" label=\\\"FB1\\\\n(#R⁺)\\\"]\\nMF1 [fillcolor=\\\"#ccf000\\\" label=\\\"MF1\\\\n(#R⁺)\\\"]\\nIV1 [fillcolor=\\\"#f5f100:#ccf000\\\" label=\\\"IV1\\\\n(#A #R⁺)\\\" penwidth=3 style=wedged]\\nIV2 [fillcolor=\\\"#bbbbbb\\\" label=\\\"IV2\\\\n(#REJ)\\\" penwidth=3]\\nIV3 [fillcolor=\\\"#f5f100:#00a80399\\\" label=\\\"IV3\\\\n(#A #I⁺)\\\" penwidth=3 style=wedged]\\nFR1 [fillcolor=\\\"#ccf000\\\" label=\\\"FR1\\\\n(#Rᵈ)\\\"]\\nFR2 [fillcolor=\\\"#ccf000\\\" label=\\\"FR2\\\\n(#Rᵈ)\\\"]\\nFR3 [fillcolor=\\\"#ccf000\\\" label=\\\"FR3\\\\n(#Rᵈ)\\\"]\\nFR4 [fillcolor=\\\"#00a80399\\\" label=\\\"FR4\\\\n(#I)\\\" penwidth=3]\\n\\nFB1 -> MF1 -> IV1 -> FR1,FR2\\nFR1 -> FR3\\nMF1 -> IV2\\nMF1 -> IV3 -> FR4\",\"lang\":\"dot\"}}],[{\"lit\":\"Implement FR1\"},{\"cb\":{\"attr\":[\"render\"],\"code\":\"node[style=filled fillcolor=\\\"#eeeeee\\\"]\\nFB1 [fillcolor=\\\"#ccf000\\\" label=\\\"FB1\\\\n(#R⁺)\\\"]\\nMF1 [