    "{\"#\":877,\"createdAt\":\"2020-08-14T05:48:03.725181Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":1,\"id\":{\"gr\":134},\"value\":[{\"lit\":\"Specifically:\"},{\"ul\":[[{\"lit\":\"result tag is dead\"}],[{\"lit\":\"result tag is out-of-scope (given field's \"},{\"mono\":\"TagGroup\"},{\"lit\":\")\"}]]}]}}}",
    "{\"#\":878,\"createdAt\":\"2020-08-14T07:19:16.455026Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":1,\"id\":{\"gr\":134},\"value\":[{\"lit\":\"Specifically:\"},{\"ul\":[[{\"lit\":\"result tag is dead\"}],[{\"lit\":\"result tag is out-of-scope (given field's \"},{\"mono\":\"TagGroup\"},{\"lit\":\")\"}],[{\"lit\":\"and the same again but for keys\"}]]}]}}}",
    "{\"#\":879,\"createdAt\":\"2020-08-14T07:31:11.624737Z\",\"event\":{\"ReqFieldCustomTextSet\":{\"fid\":1,\"id\":{\"gr\":134},\"value\":[{\"lit\":\"Specifically:\"},{\"ul\":[[{\"lit\":\"result tag is dead\"}],[{\"lit\":\"result tag is out-of-scope (given field's \"},{\"mono\":\"TagGroup\"},{\"lit\":\")\"}]]},{\"lit\":\"There's no need to mark the keys as issues as they are \"},{\"//\":[{\"lit\":\"managed\"}]},{\"lit\":\" in that they're automatically hidden from all views until the tags come back in scope.\"}]}}}",
